1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const FP_EPSILON = 1e-9;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  rune: 25,
9	};
10	
11	type Item = { type: string; cursed?: boolean };
12	type Step = { op: "quote"; items: Item[] };
13	type Scenario = { steps: Step[] };
14	
15	const sum = (numbers: number[]): number =>
16	  numbers.reduce((acc, n) => acc + n, 0);
17	
18	// round up to whole G in MHPCO's favor, using epsilon to fight FP error
19	const roundUpInMHPCOFavor = (amount: number): number =>
20	  Math.ceil(amount - FP_EPSILON);
21	
22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	const COMPONENT_BLOCK_SIZE = 3;
24	const COMPONENT_BLOCK_PRICE = 60;
25	
26	const countByType = (items: Item[]): Map<string, number> =>
27	  items.reduce(
28	    (acc, item) => acc.set(item.type, (acc.get(item.type) ?? 0) + 1),
29	    new Map<string, number>(),
30	  );
31	
32	const typeGroupPremium = (type: string, count: number): number =>
33	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE
34	    ? COMPONENT_BLOCK_PRICE
35	    : count * BASE_PREMIUM[type];
36	
37	const itemsBasePremium = (items: Item[]): number =>
38	  sum(
39	    Array.from(countByType(items), ([type, count]) =>
40	      typeGroupPremium(type, count),
41	    ),
42	  );
43	
44	const CURSE_SURCHARGE_RATE = 0.5;
45	
46	const itemSurcharges = (items: Item[]): number =>
47	  sum(
48	    items.map((item) =>
49	      item.cursed ? BASE_PREMIUM[item.type] * CURSE_SURCHARGE_RATE : 0,
50	    ),
51	  );
52	
53	const quote = (step: Step): { premium: number } => {
54	  const policyBase = itemsBasePremium(step.items);
55	  const surcharges = itemSurcharges(step.items);
56	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
57	  const total = policyBase + surcharges + firstInsurance + PROCESSING_FEE;
58	  return { premium: roundUpInMHPCOFavor(total) };
59	};
60	
61	export const runScenario = (input: unknown): unknown => {
62	  const scenario = input as Scenario;
63	  return { results: scenario.steps.map(quote) };
64	};
